function validateHtml(html) {
  let stack = [];
  let tags = html.match(/<[^>]*>/g);
  for (let tag of tags) {
    if (tag.startsWith('</')) {
      if (stack.length === 0 || stack.pop() !== tag.slice(2, -1)) {
        return false;
      }
    } else {
      stack.push(tag.slice(1, -1));
    }
  }
  return stack.length === 0;
}

