class Solution:
  def validateHtml(self, html: str) -> bool:
    stack = []
    tags = html.split('</');
    for tag in tags[1:]: # Skip the first element which is the entire string
      if tag: # Check if the tag is not empty
        if not tag.startswith('/'): # Check if the tag is an opening tag
          stack.append(tag.split('>')[0])
        else: # Check if the tag is a closing tag
          if not stack or stack.pop() != tag.split('>')[0][1:]:
            return False
    return not stack
